// Prepare payment verification data
const input = $input.first().json;
const cartJson = input.cart_json;

let productNames = '';
let orderSummary = '';

if (cartJson) {
  try {
    // 1. JSON ကို ဖြည်မည် (Parse)
    const cartData = JSON.parse(cartJson);

    // 2. Product Name များကို ကော်မာခံ၍ တွဲမည်
    productNames = cartData.map(item => item.product_name).join(', ');

    // 3. Order Summary စာသားကို တည်ဆောက်မည် (ဥပမာ: "• Snail White (x2)")
    orderSummary = cartData.map(item => {
        const qty = parseInt(item.quantity) || 1;
        return `• ${item.product_name} (x${qty})`;
    }).join('\n');


  } catch (e) {
    console.log("Error parsing cart_json");
  }
}
return [{
  json: {
    screenshot_url: $('Execute Workflow Trigger').first().json.screenshot_url || '',
    expected_amount: parseFloat(input.Total_Price) || 0,
    sender_id: input.sender_id || '',
    customer_name: input.Customer_Name || '',
    customer_phone: input.Customer_Phone || '',
    customer_address: input.Customer_Address || '',
    order_summary: orderSummary || '',
    product_name: productNames || '',
    total_price: parseFloat (input.Total_Price) || 0,
    timestamp: new Date().toISOString()
  }
}];

// Parse AI verification result
const aiOutput = $input.first().json.output;
const triggerData = $('Prepare Verification Data').first().json;
let verificationResult;

try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    verificationResult = JSON.parse(jsonMatch[0]);
  } else {
    verificationResult = {
      verification_status: 'UNREADABLE',
      notes: 'Could not parse verification result from AI',
      raw_output: aiOutput
    };
  }
} catch (e) {
  verificationResult = {
    verification_status: 'UNREADABLE',
    notes: 'Error parsing AI response: ' + e.message,
    raw_output: aiOutput
  };
}

// Carry forward all order context
verificationResult.customer_name = triggerData.customer_name;
verificationResult.customer_phone = triggerData.customer_phone;
verificationResult.customer_address = triggerData.customer_address;
verificationResult.order_summary = triggerData.order_summary;
verificationResult.sender_id = triggerData.sender_id;
verificationResult.product_name = triggerData.product_name;
verificationResult.product_image = triggerData.product_image;
verificationResult.quantity = triggerData.quantity;
verificationResult.unit_price = triggerData.unit_price;
verificationResult.price_tier = triggerData.price_tier;
verificationResult.total_price = triggerData.total_price;
verificationResult.screenshot_url = triggerData.screenshot_url;

return [{ json: verificationResult }];

