// Store all data for retrieval when admin confirms
const verifyResult = $('Parse Verification Result').first().json;
const telegramMsg = $input.first().json;

return [{
  json: {
    ...verifyResult,
    telegram_message_id: telegramMsg.message_id,
    awaiting_admin_payment_confirmation: true,
    timestamp: new Date().toISOString(),
    message:"data received"
  }
}];

const webhookData = $input.first().json;
const pendingData = $('Store Pending Payment Data').first().json;

const adminDecision = webhookData.body.status; 
const orderStatus = adminDecision === 'confirm' ? 'success' : 'fail';

// Give the AI a strict command based on the result
let instructionForAI = '';
if (orderStatus === 'success') {
  instructionForAI = "CRITICAL COMMAND: Payment verified successfully! You MUST now call the 'close_order' tool using this data. DO NOT stop working. After the close_order tool finishes, you must show the customer the final receipt.";
} else {
  instructionForAI = `CRITICAL COMMAND: Payment FAILED. The admin rejected it. You MUST immediately write a polite message in Burmese explaining that the payment could not be verified and ask the customer to resend the screenshot.`;
}

return [{
  json: {
    _AI_COMMAND_: instructionForAI, // The AI will read this first
    order_status: orderStatus,
    admin_confirmed: adminDecision === 'confirm',
    customer_name: pendingData.customer_name,
    customer_phone: pendingData.customer_phone,
    customer_address: pendingData.customer_address,
    sender_id: pendingData.sender_id,
    product_name: pendingData.product_name,
    product_image: pendingData.product_image,
    quantity: pendingData.quantity,
    unit_price: pendingData.unit_price,
    price_tier: pendingData.price_tier,
    total_price: pendingData.total_price,
    payment_method: pendingData.payment_method || '',
    transaction_id: pendingData.transaction_id || '',
    payment_screenshot_url: pendingData.screenshot_url || '',
    payment_status: orderStatus === 'success' ? 'confirmed' : 'rejected',
    verification_status: pendingData.verification_status || ''
  }
}];

// Generate unique Order ID and prepare order record
const input = $input.first().json;
const now = new Date();
const dateStr = now.toISOString().slice(0, 10).replace(/-/g, '');
const timeStr = now.toISOString().slice(11, 19).replace(/:/g, '');
const randomSuffix = Math.random().toString(36).substring(2, 6).toUpperCase();
const orderId = `ORD-${dateStr}-${timeStr}-${randomSuffix}`;

return [{
  json: {
    order_id: orderId,
    order_date: now.toISOString(),
    order_status: input.order_status || 'success',
    customer_name: input.customer_name || '',
    customer_phone: input.customer_phone || '',
    customer_address: input.customer_address || '',
    customer_fb_id: input.sender_id || '',
    product_name: input.product_name || '',
    product_image: input.product_image || '',
    quantity: parseInt(input.quantity) || 0,
    unit_price: parseFloat(input.unit_price) || 0,
    price_tier: input.price_tier || '',
    total_price: parseFloat(input.total_price) || 0,
    payment_method: input.payment_method || '',
    transaction_id: input.transaction_id || '',
    payment_screenshot_url: input.payment_screenshot_url || '',
    payment_status: input.payment_status || '',
    verification_status: input.verification_status || '',
    admin_approved: input.admin_approved || false,
    notes: input.notes || ''
  }
}];

